Event Start

	loadwwpContext.Call(&WwpContext)
	&TipoEtiqueta =  EtiquetaTIpoImpressao.RIBON // JDF por hora somente essa
	do 'MontaComboEtiqueta'

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	UnnamedTable7.Width = 250

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event 'DoUserSair'

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	wpTiposEtiquetas.Call()

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Event 'DoUserAction1'

	do 'CheckRequiredFields'
	if &CheckRequiredFieldsResult
		prcSalvaCapaModeloEtiquetaProduto.Call('NEW', &WwpContext.EmPCod, &TipEtqCod, &TipoEtiqueta, &QtdColunas, &ModeloBase, &TipEtqNom, &TipEtqFor, 0, 0, 0, 0, 0, Status_AtivoInativo.INATIVO, 0, 3, 4, 8)
		wpEtiquetaItens.Link(&WwpContext.EmpCod, &TipEtqCod)
	EndIf

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */



	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndEvent

Sub 'CheckRequiredFields'

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	&CheckRequiredFieldsResult = True
	If &QtdColunas.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','Quantidade Colunas'), DVMessageType.error, &QtdColunas.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If &ModeloBase.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','Selecione Modelo Base'), DVMessageType.error, &ModeloBase.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If &TipEtqNom.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','Nome Etiqueta'), DVMessageType.error, &TipEtqNom.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndSub

Event &TipoEtiqueta.ControlValueChanged

	do 'MontaComboEtiqueta'

EndEvent

Event &QtdColunas.ControlValueChanged

	do 'MontaComboEtiqueta'

EndEvent

Event &ModeloBase.ControlValueChanged

	&Varchar = 'EtiqPro'+&ModeloBase
	&ModeloBaseImagem.FromImage(&Varchar)

EndEvent

Sub 'MontaComboEtiqueta'

	&ModeloBase.AddItem('000', 'Selecione o Modelo Base')

	&ModeloBase.AddItem('MOD_R01', '[MOD_R01] | Nome Produto Reverse; Código Produto; Código Barras') //CROMOFORTE / ELIANDRO
	&ModeloBase.AddItem('MOD_R02', '[MOD_R02] | Código Produto; Nome Produto; Código Barras') //VERMELHA TAYGRA 2 colunas
	&ModeloBase.AddItem('MOD_R03', '[MOD_R03] | Nome Produto; Logo Pessoa; Código Produto')
	&ModeloBase.AddItem('MOD_R04', '[MOD_R04] | Nome Produto; Código Produto; Código Barras')
	&ModeloBase.AddItem('MOD_R05', '[MOD_R05] | Nome Produto; Código Barras; Código Produto')
	&ModeloBase.AddItem('MOD_R06', '[MOD_R06] | Nome Filial; Código Barras; Código Produto; Nome do Produto')
	&ModeloBase.AddItem('MOD_R07', '[MOD_R07] | Nome Produto; Código Barras; Nome empresa; Valor do Produto')
	&ModeloBase.AddItem('MOD_R08', '[MOD_R08] | Valor do Produto; Nome Produto; Código Barras; Código do Produto')
	&ModeloBase.AddItem('MOD_R09', '[MOD_R09] | Nome Filial; Código Barras; Nome Produto; Código do Produto; Preço Produto')
	&ModeloBase.AddItem('MOD_R10', '[MOD_R10] | Nome Filial; Nome Produto; Código do Produto; Código Barras; Qtd.Embalagem; Lote Produto')

EndSub

